// Filter applies the ApplicationWhereInput filter on the ApplicationQuery builder.
func (i *ApplicationWhereInput) Filter(q *ApplicationQuery) (*ApplicationQuery, error) {
	if i == nil {
		return q, nil
	}
	p, err := i.P()
	if err != nil {
		if err == ErrEmptyApplicationWhereInput {
			return q, nil
		}
		return nil, err
	}
	return q.Where(p), nil
}

